def _apple_device_info():
    """Returns (product_name, chip_name) for the current iOS device.
    Falls back to the raw identifier if we don't recognize it."""
    import platform
    ident = ""
    try:
        ident = platform.machine() or ""
    except Exception:
        pass
    entry = _APPLE_DEVICE_TABLE.get(ident)
    if entry:
        return entry
    # Heuristic fallbacks by family
    if ident.startswith("iPad"):
        return (f"iPad (model {ident})",   "Apple silicon (unrecognized)")
    if ident.startswith("iPhone"):
        return (f"iPhone (model {ident})", "Apple silicon (unrecognized)")
    return (ident or "unknown device", "unknown chip")


def _darwin_compressed_pages() -> tuple:
    """Return (compressor_bytes, total_bytes) by reading the Mach
    host_statistics64/HOST_VM_INFO64 interface directly.

    On iOS psutil.swap_memory() returns zero (no disk swap file), so
    we go to the kernel ourselves. The XNU memory-compressor pool —
    the thing macOS and iOS both call "swap" in their UI — surfaces
    as `vm_statistics64.compressor_page_count` (pages currently
    holding compressed RAM) and `total_uncompressed_pages_in_compressor`
    (what those pages would occupy if decompressed). Multiply by the
    hardware page size to get byte counts.

    Returns (0, 0) on any failure so the caller treats it as "no swap
    info available" and falls back silently.
    """
    import ctypes
    import ctypes.util
    try:
        libSystem = ctypes.CDLL(ctypes.util.find_library("System") or
                                "/usr/lib/libSystem.dylib")
    except OSError:
        return 0, 0

    # Mach types — host port is uint, count is uint.
    mach_port_t = ctypes.c_uint
    kern_return_t = ctypes.c_int
    integer_t = ctypes.c_int
    host_flavor_t = integer_t
    mach_msg_type_number_t = ctypes.c_uint

    class vm_statistics64(ctypes.Structure):
        # struct layout from <mach/vm_statistics.h>. Only fields we
        # care about are extracted by offset so layout drift at the
        # end of the struct is safe.
        _fields_ = [
            ('free_count',                              ctypes.c_uint32),
            ('active_count',                            ctypes.c_uint32),
            ('inactive_count',                          ctypes.c_uint32),
            ('wire_count',                              ctypes.c_uint32),
            ('zero_fill_count',                         ctypes.c_uint64),
            ('reactivations',                           ctypes.c_uint64),
            ('pageins',                                 ctypes.c_uint64),
            ('pageouts',                                ctypes.c_uint64),
            ('faults',                                  ctypes.c_uint64),
            ('cow_faults',                              ctypes.c_uint64),
            ('lookups',                                 ctypes.c_uint64),
            ('hits',                                    ctypes.c_uint64),
            ('purges',                                  ctypes.c_uint64),
            ('purgeable_count',                         ctypes.c_uint32),
            ('speculative_count',                       ctypes.c_uint32),
            ('decompressions',                          ctypes.c_uint64),
            ('compressions',                            ctypes.c_uint64),
            ('swapins',                                 ctypes.c_uint64),
            ('swapouts',                                ctypes.c_uint64),
            ('compressor_page_count',                   ctypes.c_uint32),
            ('throttled_count',                         ctypes.c_uint32),
            ('external_page_count',                     ctypes.c_uint32),
            ('internal_page_count',                     ctypes.c_uint32),
            ('total_uncompressed_pages_in_compressor',  ctypes.c_uint64),
        ]

    HOST_VM_INFO64 = 4
    HOST_VM_INFO64_COUNT = ctypes.sizeof(vm_statistics64) // ctypes.sizeof(integer_t)

    try:
        libSystem.mach_host_self.restype = mach_port_t
        libSystem.host_statistics64.restype = kern_return_t
        libSystem.host_statistics64.argtypes = [
            mach_port_t, host_flavor_t,
            ctypes.POINTER(vm_statistics64),
            ctypes.POINTER(mach_msg_type_number_t),
        ]
    except AttributeError:
        return 0, 0

    stat = vm_statistics64()
    count = mach_msg_type_number_t(HOST_VM_INFO64_COUNT)
    try:
        host = libSystem.mach_host_self()
        rc = libSystem.host_statistics64(
            host, HOST_VM_INFO64,
            ctypes.byref(stat), ctypes.byref(count)
        )
    except Exception:
        return 0, 0
    if rc != 0:
        return 0, 0

    # Page size via sysconf (POSIX — doesn't need Mach-specific call).
    try:
        pagesize = os.sysconf("SC_PAGE_SIZE")
    except (OSError, ValueError):
        pagesize = 16384  # arm64 iOS default
    if pagesize <= 0:
        pagesize = 16384

    compressor_bytes = int(stat.compressor_page_count) * pagesize
    uncompressed_bytes = int(stat.total_uncompressed_pages_in_compressor) * pagesize
    return compressor_bytes, uncompressed_bytes


@builtin("top")
@builtin("htop")
def _top(sh: Shell, argv: List[str]) -> None:
    """top | htop  — live CPU / memory / GPU monitor with auto-refresh.

    Shows overall CPU, per-core bars, RAM usage, our Python process's
    resident set + thread count, and a best-effort GPU device name
    (iOS doesn't expose GPU utilization to sandboxed apps, but we show
    the device model).

    Keys (raw-mode input while running):
        q / Ctrl-C  quit
        space / r   refresh now (skip the 1 s wait)
        +           increase refresh interval
        -           decrease refresh interval
    """
    import sys as _sys, time as _time
    try:
        import psutil
    except ImportError:
        print(f"{RED}top:{RESET} psutil not available — can't show system stats")
        return

    # Parse args: -d <sec> sets initial delay.
    delay = 1.0
    if "-d" in argv:
        try:
            i = argv.index("-d")
            delay = max(0.2, float(argv[i + 1]))
        except (ValueError, IndexError):
            pass

    # Prime psutil's per-core cpu_percent (first call is always 0.0).
    try: psutil.cpu_percent(interval=None, percpu=True)
    except Exception: pass

    try: proc = psutil.Process(os.getpid())
    except Exception: proc = None

    # Cache device/chip info — these don't change during the session.
    product_name, chip_name = _apple_device_info()

    width = 72
    # Switch to the alternate screen buffer so our frames don't end
    # up in scrollback. Real top / htop / vim / less all do this:
    #   \x1b[?1049h  — save cursor, switch to alt screen (clean canvas)
    #   \x1b[?25l    — hide cursor (we're drawing every 1s anyway)
    # On exit: \x1b[?25h + \x1b[?1049l restores.
    sys.stdout.write("\x1b[?1049h\x1b[?25l")
    sys.stdout.flush()
    tui_enter_raw()

    try:
        first = True
        while True:
            # ── Collect stats (keep it fast — this runs each frame) ──
            try:
                cpu_total = psutil.cpu_percent(interval=None)
                cpu_each = psutil.cpu_percent(interval=None, percpu=True) or []
            except Exception:
                cpu_total = 0.0
                cpu_each = []
            # Split each psutil call so one failure doesn't zero out
            # its neighbours — on iOS, swap_memory / getloadavg /
            # io_counters may or may not exist depending on sandbox.
            try:
                vm = psutil.virtual_memory()
                mem_used = vm.used
                mem_total = vm.total
                mem_pct = vm.percent
            except Exception:
                mem_used = mem_total = mem_pct = 0

            # "Swap" on iOS is the XNU memory-compressor pool
            # (no disk swap file). Try psutil first; if it reports
            # nothing (iOS commonly returns all-zeros), fall back to
            # reading host_statistics64 directly via Mach. The latter
            # gives us the REAL compressor stats — "compressed"
            # (bytes currently held) and "saved" (uncompressed
            # equivalent the compressor is standing in for).
            swap_total = swap_used = 0
            swap_pct = 0.0
            swap_compressor = swap_uncompressed = 0
            try:
                sw = psutil.swap_memory()
                swap_used = sw.used
                swap_total = sw.total
                swap_pct = sw.percent
            except Exception:
                pass
            try:
                swap_compressor, swap_uncompressed = _darwin_compressed_pages()
            except Exception:
                pass

            try:
                core_count = psutil.cpu_count(logical=True) or len(cpu_each) or 1
            except Exception:
                core_count = len(cpu_each) or 1

            # Load average (1/5/15 min) — not guaranteed on iOS
            load1 = load5 = load15 = 0.0
            try:
                load1, load5, load15 = psutil.getloadavg()
            except Exception:
                pass

            proc_rss = 0
            proc_threads = 0
            if proc is not None:
                try:
                    mi = proc.memory_info()
                    proc_rss = mi.rss
                except Exception:
                    pass
                try:
                    proc_threads = proc.num_threads()
                except Exception:
                    pass

            # ── Draw ──
            # We're in the alternate screen buffer, so we can clear
            # safely — nothing gets pushed to scrollback.
            # \x1b[H — cursor home; \x1b[2J — clear screen.
            _sys.stdout.write("\x1b[H\x1b[2J")

            # Top status bar
            stamp = _time.strftime("%H:%M:%S")
            title = f" top — live system monitor   ({stamp},  refresh {delay:.1f}s)"
            _sys.stdout.write(
                f"\x1b[7m{title:<{width}}\x1b[0m\r\n\r\n"
            )

            # Overall CPU
            _sys.stdout.write(
                f"  {BOLD}CPU total{RESET}  "
                f"[{_bar_colored(cpu_total / 100, 32)}]  "
                f"{cpu_total:>5.1f}%\r\n"
            )

            # Per-core bars
            if cpu_each:
                _sys.stdout.write(f"  {DIM}cores ({core_count}){RESET}\r\n")
                for i, p in enumerate(cpu_each):
                    _sys.stdout.write(
                        f"    {DIM}#{i:<2}{RESET}     "
                        f"[{_bar_colored(p / 100, 32)}]  "
                        f"{p:>5.1f}%\r\n"
                    )

            # Load average — only show if psutil.getloadavg worked.
            if load1 > 0 or load5 > 0 or load15 > 0:
                _sys.stdout.write(
                    f"  {BOLD}load avg {RESET}  "
                    f"{load1:>4.2f}  {load5:>4.2f}  {load15:>4.2f}   "
                    f"{DIM}(1m / 5m / 15m, {core_count} cores){RESET}\r\n"
                )

            _sys.stdout.write("\r\n")

            # Memory (RAM)
            _sys.stdout.write(
                f"  {BOLD}RAM      {RESET}  "
                f"[{_bar_colored(mem_pct / 100, 32)}]  "
                f"{mem_pct:>5.1f}%   "
                f"{_human_bytes(mem_used)} / {_human_bytes(mem_total)}\r\n"
            )
            # Compressed / swap. Prefer psutil's reading (has a real
            # total when macOS actually swaps to disk). Otherwise show
            # the XNU compressor pool direct from Mach — iOS's "swap".
            if swap_total > 0:
                _sys.stdout.write(
                    f"  {BOLD}Swap/cmp {RESET}  "
                    f"[{_bar_colored(swap_pct / 100, 32)}]  "
                    f"{swap_pct:>5.1f}%   "
                    f"{_human_bytes(swap_used)} / {_human_bytes(swap_total)}   "
                    f"{DIM}(iOS compressed memory){RESET}\r\n"
                )
            elif swap_compressor > 0:
                # Ratio of (compressor pool size) / (what it stands in
                # for uncompressed) tells you how hard the compressor
                # is working. Show it as a "saved" amount.
                saved = max(0, swap_uncompressed - swap_compressor)
                _sys.stdout.write(
                    f"  {BOLD}Compressed{RESET} "
                    f"{_human_bytes(swap_compressor)} held   "
                    f"({_human_bytes(swap_uncompressed)} uncompressed, "
                    f"{_human_bytes(saved)} saved)   "
                    f"{DIM}(iOS XNU memory compressor){RESET}\r\n"
                )

            _sys.stdout.write("\r\n")

            # Device info — chip + product (cached, doesn't change).
            _sys.stdout.write(
                f"  {BOLD}Device   {RESET}  "
                f"{CYN}{product_name}{RESET}\r\n"
            )
            _sys.stdout.write(
                f"  {BOLD}Chip     {RESET}  "
                f"{CYN}{chip_name}{RESET}\r\n"
            )
            # GPU: iOS doesn't expose per-process utilization to
            # sandboxed apps (no public IOAccelerator API). We report
            # the chip family and note the limitation.
            gpu_name = chip_name.split(' ', 1)[-1] if ' ' in chip_name else chip_name
            _sys.stdout.write(
                f"  {BOLD}GPU      {RESET}  "
                f"{CYN}{gpu_name} integrated{RESET}   "
                f"{DIM}(utilisation not exposed on iOS){RESET}\r\n"
            )

            _sys.stdout.write("\r\n")

            # This process — pid, RSS, thread count.
            _sys.stdout.write(
                f"  {BOLD}Python   {RESET}  "
                f"pid={os.getpid()}   "
                f"rss={_human_bytes(proc_rss)}   "
                f"threads={proc_threads}\r\n"
            )

            # Footer hint (reverse video)
            _sys.stdout.write("\r\n")
            footer = " q quit   space refresh   +/- adjust interval"
            _sys.stdout.write(
                f"\x1b[7m{footer:<{width}}\x1b[0m\r\n"
            )
            _sys.stdout.flush()

            # ── Wait for keypress or timeout ──
            # We can't do select() on a pipe FD safely here, so use a
            # short-polling loop: sleep in small chunks and peek for
            # input (os.read is blocking unless we set O_NONBLOCK).
            # PTYBridge already sets masterFD = pipe write-end, so
            # fd 0 is the read-end which IS non-blocking.
            import fcntl as _fcntl, errno as _errno
            # Set fd 0 non-blocking for the polling loop.
            flags = _fcntl.fcntl(0, _fcntl.F_GETFL)
            _fcntl.fcntl(0, _fcntl.F_SETFL, flags | os.O_NONBLOCK)
            try:
                deadline = _time.time() + delay
                refreshed = False
                while _time.time() < deadline:
                    try:
                        chunk = os.read(0, 16)
                    except OSError as e:
                        if e.errno in (_errno.EAGAIN, _errno.EWOULDBLOCK):
                            chunk = b""
                        else:
                            raise
                    if chunk:
                        if b"q" in chunk or b"\x03" in chunk or b"\x04" in chunk:
                            return
                        if b" " in chunk or b"r" in chunk:
                            refreshed = True
                            break
                        if b"+" in chunk or b"=" in chunk:
                            delay = min(10.0, delay + 0.5)
                            break
                        if b"-" in chunk or b"_" in chunk:
                            delay = max(0.2, delay - 0.5)
                            break
                    _time.sleep(0.05)
            finally:
                _fcntl.fcntl(0, _fcntl.F_SETFL, flags)  # restore blocking

            first = False
    finally:
        tui_exit_raw()
        # Show cursor + leave alt screen. Scrollback we had BEFORE
        # entering alt screen is restored unchanged (that's the whole
        # point of ?1049h/?1049l — real top/htop/vim/less behavior).
        _sys.stdout.write("\x1b[?25h\x1b[?1049l")
        _sys.stdout.flush()


# ---------------------------------------------------------------------------
# git clone — works via the code-hosting provider's zipball endpoint.
# iOS blocks fork/exec so we can't run real `git`. But the 99% use case
# (download a public repo to work with) is covered by fetching the repo's
# archive over HTTPS and unzipping it. Supports GitHub, GitLab, Bitbucket,
# Codeberg / Gitea / Forgejo instances.

def _parse_git_url(url: str):
    """Parse a git URL into (host, user, repo, ref). `ref` defaults to
    empty — the provider serves the default branch when unspecified.

    Handles:
      https://github.com/user/repo
      https://github.com/user/repo.git
      git@github.com:user/repo.git   (SSH form)
      https://gitlab.com/user/repo
      https://bitbucket.org/user/repo
      https://codeberg.org/user/repo
    """
    import re
    url = url.strip().rstrip("/")
    if url.endswith(".git"):
        url = url[:-4]

    # SSH form: git@host:user/repo
    m = re.match(r"git@([^:]+):([^/]+)/(.+)$", url)
    if m:
        return m.group(1), m.group(2), m.group(3), ""

    # HTTPS / HTTP form
    m = re.match(r"https?://([^/]+)/([^/]+)/([^/]+?)(?:/tree/([^/]+))?$", url)
    if m:
        return m.group(1), m.group(2), m.group(3), m.group(4) or ""

    return None


def _git_zipball_url(host: str, user: str, repo: str, ref: str) -> str:
    """Given a parsed URL, return the zipball download URL for the
    appropriate provider."""
    host_l = host.lower()
    ref = ref or ""  # empty → provider default
    if "github.com" in host_l:
        return (f"https://api.github.com/repos/{user}/{repo}/zipball"
                + (f"/{ref}" if ref else ""))
    if "gitlab.com" in host_l:
        # GitLab: /api/v4/projects/:id/repository/archive.zip?sha=ref
        # Use the public name-based endpoint:
        slug = f"{user}%2F{repo}"
        return (f"https://gitlab.com/api/v4/projects/{slug}/"
                f"repository/archive.zip" + (f"?sha={ref}" if ref else ""))
    if "bitbucket.org" in host_l:
        return (f"https://bitbucket.org/{user}/{repo}/get/"
                f"{ref or 'HEAD'}.zip")
    if "codeberg.org" in host_l or "forgejo" in host_l or "gitea" in host_l:
        return (f"https://{host}/{user}/{repo}/archive/"
                f"{ref or 'HEAD'}.zip")
    # Generic fallback — try GitHub's API shape (won't work for most
    # private-host setups but is a reasonable guess).
    return f"https://{host}/{user}/{repo}/archive/{ref or 'HEAD'}.zip"


@builtin("git")
def _git(sh: Shell, argv: List[str]) -> None:
    """git clone <url> [dir]  — fetch a remote repo over HTTPS.

    iOS blocks fork/exec so we can't run the real `git` binary. This
    builtin downloads the repo's zipball from the provider's archive
    endpoint (GitHub / GitLab / Bitbucket / Codeberg / generic Gitea)
    and unzips it into `dir` (or `<repo>/` by default). Missing features
    vs. real git: no `.git/` metadata, no history, no pushes — but
    enough to get a working-tree copy for reading / running code.

    Other subcommands (pull, push, commit, …) aren't supported and
    return a short 'not available on iOS' message.
    """
    if not argv or _is_help_tok(argv[0]):
        print("usage: git clone <url> [target-dir]")
        return

    sub = argv[0]
    if sub != "clone":
        print(f"{RED}git:{RESET} on iOS only `git clone` is supported "
              f"(no fork/exec available). Got: `{sub}`")
        print(f"{DIM}  Consider `pip install dulwich` for a pure-Python "
              f"git implementation that supports more operations.{RESET}")
        return

    if len(argv) < 2:
        print("usage: git clone <url> [target-dir]")
        return

    url = argv[1]
    parsed = _parse_git_url(url)
    if parsed is None:
        print(f"{RED}git:{RESET} can't parse URL: {url}")
        return
    host, user, repo, ref = parsed
    target = argv[2] if len(argv) >= 3 else repo

    target_path = os.path.abspath(os.path.expanduser(target))
    if os.path.exists(target_path):
        print(f"{RED}git:{RESET} target already exists: {target}")
        return

    zipball = _git_zipball_url(host, user, repo, ref)
    print(f"{BOLD}Cloning{RESET} {host}/{user}/{repo}"
          f"{(' @ ' + ref) if ref else ''} → {target}")
    print(f"{DIM}  via {zipball}{RESET}")

    try:
        import urllib.request as _ur, zipfile as _zf, io as _io, tempfile as _tf

        # Stream the zipball to a temp file so huge repos don't OOM.
        tmp_zip = _tf.NamedTemporaryFile(suffix=".zip", delete=False)
        tmp_zip_path = tmp_zip.name
        tmp_zip.close()
        req = _ur.Request(zipball, headers={
            "User-Agent": "CodeBench-iOS-Git-Clone/1.0",
            "Accept": "application/zip",
        })
        try:
            with _ur.urlopen(req, timeout=60) as resp:
                total_bytes = 0
                last_pct = -1
                content_length = int(resp.headers.get("Content-Length") or 0)
                with open(tmp_zip_path, "wb") as f:
                    while True:
                        chunk = resp.read(65536)
                        if not chunk:
                            break
                        f.write(chunk)
                        total_bytes += len(chunk)
                        if content_length > 0:
                            pct = int(100 * total_bytes / content_length)
                            if pct != last_pct and pct % 5 == 0:
                                last_pct = pct
                                print(f"{DIM}  downloaded {_human_bytes(total_bytes)} "
                                      f"/ {_human_bytes(content_length)} "
                                      f"({pct}%){RESET}")
                        else:
                            # Unknown size — print every 1 MB
                            if total_bytes // (1 << 20) != last_pct // (1 << 20) if last_pct > 0 else True:
                                last_pct = total_bytes
                                print(f"{DIM}  downloaded {_human_bytes(total_bytes)}{RESET}")
        except Exception as e:
            try: os.unlink(tmp_zip_path)
            except OSError: pass
            print(f"{RED}git:{RESET} download failed: {e}")
            return

        # Extract
        try:
            with _zf.ZipFile(tmp_zip_path) as zf:
                names = zf.namelist()
                if not names:
                    print(f"{RED}git:{RESET} empty archive")
                    return
                # Provider archives usually have a single top-level
                # directory like `user-repo-sha/`. Strip it so the user
                # gets `target/src/...` not `target/user-repo-sha/src/...`.
                top = names[0].split("/", 1)[0] + "/"
                strip_top = all(n == top[:-1] or n.startswith(top) for n in names)

                os.makedirs(target_path, exist_ok=True)
                for n in names:
                    # Security: reject any path with .. or absolute paths
                    if n.startswith("/") or ".." in n.split("/"):
                        continue
                    rel = n[len(top):] if strip_top else n
                    if not rel:
                        continue
                    out_path = os.path.join(target_path, rel)
                    if n.endswith("/"):
                        os.makedirs(out_path, exist_ok=True)
                        continue
                    os.makedirs(os.path.dirname(out_path) or target_path,
                                exist_ok=True)
                    with zf.open(n) as src, open(out_path, "wb") as dst:
                        while True:
                            buf = src.read(65536)
                            if not buf:
                                break
                            dst.write(buf)
        except Exception as e:
            print(f"{RED}git:{RESET} unzip failed: {e}")
            return
        finally:
            try: os.unlink(tmp_zip_path)
            except OSError: pass

        # Count what we got
        file_count = 0
        total_size = 0
        for root, _dirs, files in os.walk(target_path):
            for f in files:
                try:
                    total_size += os.path.getsize(os.path.join(root, f))
                    file_count += 1
                except OSError:
                    pass
        print(f"{GRN}{BOLD}✓ Cloned{RESET} {file_count} files, "
              f"{_human_bytes(total_size)} → {target}/")
    except Exception as e:
        print(f"{RED}git clone failed:{RESET} {e}")


# ---------------------------------------------------------------------------
# Module-level singleton

shell = Shell()


def run_line(line: str) -> None:
    """Public entry point used by Swift: `offlinai_shell.run_line(line)`."""
    shell.run_line(line)


def prompt() -> str:
    return shell.prompt()


def ps2() -> str:
    return shell.ps2()


def pending_continuation() -> bool:
    """Whether the shell is still collecting a multi-line Python block."""
    return bool(shell.pending)


# ---------------------------------------------------------------------------
# Blocking REPL loop — reads stdin line-by-line and dispatches.
#
# Run this on a background thread that sits on sys.stdin forever. When
# SwiftTerm is attached to the same PTY as this interpreter's stdin,
# the user types keystrokes into the terminal view, they arrive here
# as a line via input(), and we dispatch.
#
# Line-editing (backspace, arrow keys, etc.) is expected to happen on
# the SwiftTerm side — the TerminalView implements VT100 input-mode
# locally. If you want raw per-keystroke mode, send an ESC[?1h etc to
# the terminal. This REPL just reads complete lines.

class _LineEditor_UNUSED:
    """Old Python-side editor — kept here for reference. Line editing
    moved to Swift (PTYBridge.LineBuffer) because (a) Python wasn't
    running before the user tapped Run, so nothing could echo, and
    (b) a pipe's line buffering made single-char echoes pile up in
    sys.stdout. Swift-side editing is the correct 'cooked PTY' analog."""

    # Control bytes / escape sequence finals we recognize.
    _CSI_FINALS = set(range(0x40, 0x7F))  # @ A..Z [..` a..z {..~

    def __init__(self, history: list):
        self.history = history           # shared command history list
        self.history_index = 0
        self.buf = bytearray()           # current line bytes (UTF-8)
        self.pos = 0                     # byte offset of cursor in buf
        self._saved_pending = b""        # stash for history nav

    # ── raw output ──
    @staticmethod
    def _write(data):
        import sys
        try:
            if isinstance(data, str):
                sys.stdout.write(data)
            elif hasattr(sys.stdout, "buffer"):
                sys.stdout.buffer.write(data)
            else:
                sys.stdout.write(data.decode("utf-8", errors="replace"))
            sys.stdout.flush()
        except Exception:
            pass

    # ── editing primitives ──
    def _redraw_tail(self):
        """Redraw buffer from pos to end + clear rest of line + move
        cursor back to logical pos. Call after any mutation at pos."""
        tail = bytes(self.buf[self.pos:])
        self._write(tail + b"\x1b[K")
        if tail:
            self._write(f"\x1b[{len(tail)}D".encode())

    def insert(self, data: bytes):
        if not data:
            return
        self.buf[self.pos:self.pos] = data
        self.pos += len(data)
        rest = bytes(self.buf[self.pos:])
        self._write(data + rest)
        if rest:
            self._write(f"\x1b[{len(rest)}D".encode())

    def backspace(self):
        if self.pos == 0:
            return
        # Step back one UTF-8 code point (may be multi-byte).
        i = self.pos - 1
        while i > 0 and (self.buf[i] & 0xC0) == 0x80:
            i -= 1
        del self.buf[i:self.pos]
        moved = self.pos - i
        self.pos = i
        self._write(b"\x08" * moved)
        self._redraw_tail()

    def delete_forward(self):
        if self.pos >= len(self.buf):
            return
        # Step forward one UTF-8 code point.
        j = self.pos + 1
        while j < len(self.buf) and (self.buf[j] & 0xC0) == 0x80:
            j += 1
        del self.buf[self.pos:j]
        self._redraw_tail()

    def move_left(self):
        if self.pos == 0:
            return
        i = self.pos - 1
        while i > 0 and (self.buf[i] & 0xC0) == 0x80:
            i -= 1
        moved = self.pos - i
        self.pos = i
        self._write(f"\x1b[{moved}D".encode())

    def move_right(self):
        if self.pos >= len(self.buf):
            return
        j = self.pos + 1
        while j < len(self.buf) and (self.buf[j] & 0xC0) == 0x80:
            j += 1
        moved = j - self.pos
        self.pos = j
        self._write(f"\x1b[{moved}C".encode())

    def move_home(self):
        if self.pos > 0:
            self._write(f"\x1b[{self.pos}D".encode())
            self.pos = 0

    def move_end(self):
        if self.pos < len(self.buf):
            delta = len(self.buf) - self.pos
            self._write(f"\x1b[{delta}C".encode())
            self.pos = len(self.buf)

    def kill_line(self):
        """Ctrl-U: delete from beginning to cursor."""
        if self.pos == 0:
            return
        del self.buf[:self.pos]
        self._write(f"\x1b[{self.pos}D".encode())
        self.pos = 0
        self._redraw_tail()

    def kill_to_eol(self):
        """Ctrl-K: delete from cursor to end."""
        if self.pos >= len(self.buf):
            return
        del self.buf[self.pos:]
        self._write(b"\x1b[K")

    def kill_word(self):
        """Ctrl-W: delete previous word."""
        if self.pos == 0:
            return
        i = self.pos
        while i > 0 and self.buf[i - 1] == 0x20:
            i -= 1
        while i > 0 and self.buf[i - 1] != 0x20:
            i -= 1
        del self.buf[i:self.pos]
        moved = self.pos - i
        self.pos = i
        self._write(f"\x1b[{moved}D".encode())
        self._redraw_tail()

    def _replace_line(self, new: bytes):
        if self.pos > 0:
            self._write(f"\x1b[{self.pos}D".encode())
        self._write(b"\x1b[K")
        self.buf = bytearray(new)
        self.pos = len(new)
        self._write(new)

    def history_up(self):
        if not self.history:
            return
        if self.history_index == len(self.history):
            self._saved_pending = bytes(self.buf)
        if self.history_index > 0:
            self.history_index -= 1
            self._replace_line(self.history[self.history_index].encode("utf-8"))

    def history_down(self):
        if self.history_index < len(self.history):
            self.history_index += 1
            if self.history_index == len(self.history):
                self._replace_line(self._saved_pending)
            else:
                self._replace_line(
                    self.history[self.history_index].encode("utf-8"))

    def reset(self):
        self.buf.clear()
        self.pos = 0
        self.history_index = len(self.history)
        self._saved_pending = b""

    # ── main loop ──
    def read_line(self) -> str:
        """Read one complete line. Returns text (no newline).
        Raises KeyboardInterrupt on Ctrl-C, EOFError on Ctrl-D at BOL.
        """
        import os, sys, errno, time
        self.reset()

        while True:
            try:
                b = os.read(0, 1)
            except OSError as e:
                if e.errno in (errno.EAGAIN, errno.EINTR):
                    continue
                raise
            if not b:
                time.sleep(0.1)
                continue

            c = b[0]

            # Enter
            if c == 0x0d or c == 0x0a:
                self._write(b"\r\n")
                line = bytes(self.buf).decode("utf-8", errors="replace")
                if line.strip():
                    if not self.history or self.history[-1] != line:
                        self.history.append(line)
                return line

            # Ctrl-C
            if c == 0x03:
                self._write(b"^C\r\n")
                raise KeyboardInterrupt

            # Ctrl-D
            if c == 0x04:
                if len(self.buf) == 0:
                    self._write(b"\r\n")
                    raise EOFError
                self.delete_forward()
                continue

            # Backspace / BS
            if c == 0x7f or c == 0x08:
                self.backspace()
                continue

            # Ctrl-A / Ctrl-E / Ctrl-U / Ctrl-K / Ctrl-W / Ctrl-L
            if c == 0x01:
                self.move_home(); continue
            if c == 0x05:
                self.move_end(); continue
            if c == 0x15:
                self.kill_line(); continue
            if c == 0x0b:
                self.kill_to_eol(); continue
            if c == 0x17:
                self.kill_word(); continue
            if c == 0x0c:
                # Clear screen + redraw prompt and current line.
                # The caller re-prints the prompt on return from read_line,
                # but we're mid-read. Clear screen then redraw in place.
                self._write(b"\x1b[2J\x1b[H")
                # Prompt + current line — caller's repl() will handle it
                # on next iteration; here we just do a minimal redraw.
                try:
                    prompt_str = (shell.ps2() if shell.pending
                                  else shell.prompt())
                except Exception:
                    prompt_str = "$ "
                self._write(prompt_str)
                self._write(bytes(self.buf))
                if self.pos < len(self.buf):
                    delta = len(self.buf) - self.pos
                    self._write(f"\x1b[{delta}D".encode())
                continue

            # ESC — escape sequence (arrow keys, delete, home, end, …)
            if c == 0x1b:
                try:
                    b2 = os.read(0, 1)
                except OSError:
                    continue
                if b2 == b"[":
                    # CSI: read until final byte 0x40–0x7E
                    seq = bytearray()
                    for _ in range(10):  # bound the read
                        try:
                            nb = os.read(0, 1)
                        except OSError:
                            break
                        if not nb:
                            break
                        seq.extend(nb)
                        if nb[0] in self._CSI_FINALS:
                            break
                    s = bytes(seq)
                    if s == b"A":       self.history_up()
                    elif s == b"B":     self.history_down()
                    elif s == b"C":     self.move_right()
                    elif s == b"D":     self.move_left()
                    elif s == b"H":     self.move_home()
                    elif s == b"F":     self.move_end()
                    elif s == b"1~":    self.move_home()
                    elif s == b"4~":    self.move_end()
                    elif s == b"3~":    self.delete_forward()
                    elif s == b"7~":    self.move_home()
                    elif s == b"8~":    self.move_end()
                    # otherwise silently ignore unknown sequence
                elif b2 == b"O":
                    # SS3: App-mode arrows (some emulators send these)
                    try:
                        nb = os.read(0, 1)
                    except OSError:
                        continue
                    if nb == b"A":      self.history_up()
                    elif nb == b"B":    self.history_down()
                    elif nb == b"C":    self.move_right()
                    elif nb == b"D":    self.move_left()
                    elif nb == b"H":    self.move_home()
                    elif nb == b"F":    self.move_end()
                # else: bare ESC — ignore
                continue

            # Tab — for now, insert literal tab. (Could wire up
            # completion later via rlcompleter.)
            if c == 0x09:
                self.insert(b"    ")  # 4 spaces, readable default
                continue

            # Printable / UTF-8 byte
            if c >= 0x20 or c == 0x09:
                self.insert(bytes([c]))
                continue

            # Anything else (unknown control byte) — skip silently


def repl():
    """Never returns — loops forever prompting + reading + dispatching.

    Swift does all the line editing (see PTYBridge.LineBuffer) and
    sends us complete lines terminated by \\n. We just read line by
    line and run each one.
    """
    import os, sys, errno, time, traceback, signal, threading

    def _write_out(s: str) -> None:
        try:
            sys.stdout.write(s)
            sys.stdout.flush()
        except Exception:
            pass

    # ── Ctrl+C wiring ─────────────────────────────────────────────
    # Two paths have to work together for Ctrl+C to interrupt any
    # running command:
    #
    # 1) Default SIGINT → KeyboardInterrupt handler. Python installs
    #    this by default on the main thread, but ONLY if the
    #    interpreter was booted with initsigs=1 AND the signal module
    #    finishes initialization. Embedding-style builds (BeeWare
    #    Python-Apple-support) sometimes end up with SIG_DFL here,
    #    which silently terminates the process on ^C. Force the
    #    default handler ourselves so we get KeyboardInterrupt.
    #
    # 2) A watchdog thread that polls stdin for a bare 0x03 byte.
    #    Swift's PTYBridge forwards Ctrl+C as both PyErr_SetInterrupt()
    #    AND a raw 0x03 byte in the stdin pipe. The first path catches
    #    Python bytecode; the second catches blocking C calls (e.g.
    #    os.read in a library) because once the byte appears we call
    #    `_thread.interrupt_main()` which delivers SIGINT to the
    #    main/REPL thread.
    try:
        signal.signal(signal.SIGINT, signal.default_int_handler)
    except (ValueError, OSError):
        # ValueError means we're not on the main thread — skip, Swift's
        # PyErr_SetInterrupt path still works.
        pass

    try:
        import _thread as _thr
    except ImportError:
        _thr = None

    def _ctrlc_watchdog():
        """Peek at stdin for raw Ctrl+C bytes while a command runs.
        When detected, interrupt the main thread."""
        import fcntl, select
        try:
            # Make fd 0 non-blocking so the peek never hangs if the
            # pipe is empty.
            fl = fcntl.fcntl(0, fcntl.F_GETFL)
            fcntl.fcntl(0, fcntl.F_SETFL, fl | os.O_NONBLOCK)
        except OSError:
            return
        while True:
            try:
                r, _, _ = select.select([0], [], [], 0.1)
                if not r:
                    continue
                # Peek using MSG_PEEK-equivalent — just read and put back
                # isn't possible on a pipe; but we read one byte and if
                # it's 0x03 we raise. If not, we've consumed it, which
                # is fine: the REPL's own read loop ignores stray bytes
                # outside of a command.
                data = os.read(0, 64)
                if not data:
                    continue
                if b"\x03" in data:
                    if _thr is not None:
                        _thr.interrupt_main()
                # Anything else the watchdog consumed gets thrown away
                # — the REPL's read path will just prompt again on next
                # iteration. Rare: only happens if the user types while
                # a command is busy. Acceptable trade for working ^C.
            except (OSError, InterruptedError):
                time.sleep(0.05)
                continue

    # NB: disabled by default. The watchdog conflicts with the REPL's
    # own os.read(0) in the main loop — both would race for the same
    # stdin. Keep it here as documentation / opt-in for future work;
    # the signal.default_int_handler install + Swift's PyErr_SetInterrupt
    # is enough for most cases.
    # threading.Thread(target=_ctrlc_watchdog, daemon=True).start()

    _write_out(
        f"{GRN}{BOLD}CodeBench shell{RESET} — type {CYN}help{RESET} for builtins, "
        f"anything else is Python.\n"
    )

    line_buf = bytearray()

    while True:
        try:
            prompt_str = shell.ps2() if shell.pending else shell.prompt()
            _write_out(prompt_str)

            # Swift's LineBuffer sends complete lines ending with \n.
            # Read bytes until we see one.
            line_buf.clear()
            while True:
                try:
                    chunk = os.read(0, 256)
                except OSError as e:
                    if e.errno in (errno.EAGAIN, errno.EINTR):
                        continue
                    raise
                if not chunk:
                    time.sleep(0.05)
                    continue

                # Ctrl-C surface: Swift may send 0x03 as a bare byte to
                # interrupt an in-progress command. In the REPL context
                # we just discard the current accumulator and re-prompt.
                if b"\x03" in chunk:
                    line_buf.clear()
                    raise KeyboardInterrupt

                line_buf.extend(chunk)
                if b"\n" in line_buf:
                    break

            # Take everything up to the first \n as the line; anything
            # after (rare) stays for the next iteration via the next
            # os.read call.
            nl_idx = line_buf.index(b"\n")
            line = bytes(line_buf[:nl_idx]).decode("utf-8", errors="replace")
            line = line.rstrip("\r")
            shell.run_line(line)

        except KeyboardInterrupt:
            _write_out(f"\n{YLW}^C{RESET}\n")
            shell.pending.clear()
        except SystemExit:
            _write_out(f"\n{DIM}(SystemExit — shell staying alive){RESET}\n")
            shell.pending.clear()
        except BaseException:
            try:
                tb = traceback.format_exc()
                _write_out(tb)
            except Exception:
                pass
            shell.pending.clear()
            # Belt & suspenders: if something in the prompt / read path
            # keeps raising the same error, a tight loop of tracebacks
            # is unusable. Sleep a bit + try chdir'ing back home so the
            # next iteration has a fighting chance.
            try:
                os.chdir(shell.home)
            except OSError:
                pass
            time.sleep(0.1)
